import type { FormulaCard } from "./schema";
import type { NCERTReference } from "@/lib/chemistry/reactions";

type FormulaChapterKey =
  | "atomic-structure"
  | "physical-chemistry"
  | "states-of-matter"
  | "thermodynamics"
  | "equilibrium"
  | "electrochemistry"
  | "chemical-kinetics"
  | "solutions";

const ncertByChapter: Record<FormulaChapterKey, NCERTReference> = {
  "atomic-structure": { class: 11, chapter: "Structure of Atom", topic: "Atomic structure formulas" },
  "physical-chemistry": { class: 11, chapter: "Some Basic Concepts of Chemistry", topic: "Mole concept and concentration terms" },
  "states-of-matter": { class: 11, chapter: "States of Matter", topic: "Ideal gases and kinetic theory" },
  thermodynamics: { class: 11, chapter: "Thermodynamics", topic: "Thermodynamic state functions" },
  equilibrium: { class: 11, chapter: "Equilibrium", topic: "Chemical and ionic equilibrium" },
  electrochemistry: { class: 12, chapter: "Electrochemistry", topic: "Cells, conductance, and electrolysis" },
  "chemical-kinetics": { class: 12, chapter: "Chemical Kinetics", topic: "Rate laws and activation energy" },
  solutions: { class: 12, chapter: "Solutions", topic: "Vapour pressure and colligative properties" },
};

function slugify(value: string): string {
  return value.toLowerCase().replace(/[^a-z0-9]+/g, "-").replace(/^-+|-+$/g, "");
}

function list(value: string): string[] {
  return value.split(";").map((item) => item.trim()).filter(Boolean);
}

function f(
  chapterKey: FormulaChapterKey,
  name: string,
  formula: string,
  topic: string,
  variables: string,
  units: string,
  derivation: string,
  exceptions: string,
  relatedPYQ: string[]
): FormulaCard {
  const ncertReference = ncertByChapter[chapterKey];
  return {
    id: slugify(`${chapterKey}-${name}`),
    formula,
    name,
    chapter: ncertReference.chapter,
    topic,
    variables: list(variables),
    units,
    derivation,
    exceptions: list(exceptions),
    ncertReference,
    relatedPYQ,
  };
}

